package com.google.gson.internal;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  @Test
  void write_CallsTypeAdaptersJsonElementWrite() throws IOException {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> typeAdaptersMockedStatic = Mockito.mockStatic(TypeAdapters.class)) {
      // Spy on the existing JSON_ELEMENT instance
      var jsonElementAdapterSpy = spy(TypeAdapters.JSON_ELEMENT);

      // Use block lambda to satisfy compiler for void functional interface
      typeAdaptersMockedStatic.when(() -> {
        // no-op to satisfy void interface, but we want to mock the field access
      }).thenAnswer(invocation -> null);

      // Instead of mocking the field access via when, use Mockito's doReturn on the static field via reflection
      // But since JSON_ELEMENT is a static final field, we can't replace it easily.
      // So instead, we stub the static method that returns JSON_ELEMENT if any, or mock the call indirectly.

      // Alternatively, mock TypeAdapters.JSON_ELEMENT.write directly using spy
      // So we stub the static field by using Mockito's inline mock on the field via reflection:
      // Since the static field is final, we cannot reassign it directly.
      // But we can mock the static method that uses it, or just spy on the field and verify the call.

      // So call the method under test with the spy:
      // To do this, we make the static field return our spy via the static mock:
      typeAdaptersMockedStatic.when(() -> TypeAdapters.JSON_ELEMENT).thenReturn(jsonElementAdapterSpy);

      // Call the method under test
      Streams.write(element, writer);

      // Verify that TypeAdapters.JSON_ELEMENT.write(writer, element) was called
      verify(jsonElementAdapterSpy).write(writer, element);
    }
  }
}
